class Solution:
    def reversePrefix(self, s, k):
        # Independent construction: swap characters in place with two pointers
        # instead of slicing, to catch a boundary mistake in the slice-based solution.
        chars = list(s)
        i, j = 0, k - 1
        while i < j:
            chars[i], chars[j] = chars[j], chars[i]
            i += 1
            j -= 1
        return ''.join(chars)

